if not functionsloaded then glyph = function(a) local b = false local c = 1 local glyph = GetGlyphSocketInfo(c) while glyph do local d = select(3, GetGlyphSocketInfo(c)) if d == a then b = true break end c = c + 1 glyph = GetGlyphSocketInfo(c) end return b end function CanAttack() if UnitExists(&quot;target&quot;) and UnitCanAttack(&quot;player&quot;, &quot;target&quot;) == 1 then return true end end function UnX() if UnitExists(&quot;target&quot;) then return true end end function pMove() if GetUnitSpeed(&quot;player&quot;) &gt;= 3 then return true end end function pStay() if GetUnitSpeed(&quot;player&quot;) == 0 then return true end end function inCombat() if UnitAffectingCombat(&quot;player&quot;) ~= nil then return true end end function getHp(e) if UnitExists(e) ~= nil then return 100 * UnitHealth(e) / UnitHealthMax(e) end end function CalculateHP(f) local g = 100 * UnitHealth(f) / UnitHealthMax(f) if g then return g else return 100 end end CooldownRemains = nil function CooldownRemains(h) local i, j, k = GetSpellCooldown(h) if i &gt; 0 and j &gt; 1.5 and not gcd() then return i + j - GetTime() else return false end end ItemCooldownRemains = nil function ItemCooldownRemains(l) local i, j, k = GetItemCooldown(l) if i &gt; 0 and j &gt; 1.5 then return i + j - GetTime() else return false end end function gcd() local m, n = GetSpellCooldown(61304) if n ~= 0 then return true else return false end end function rangeCheck(o, e) if IsSpellInRange(GetSpellInfo(o), e) == 1 and not gcd() then return true end end function rangeCheck2(o, e) if IsSpellInRange(GetSpellInfo(o), e) == 1 then return true end end function threat(f) if UnitExists(f) and UnitThreatSituation(f) ~= nil then return UnitThreatSituation(f) else return 0 end end valid = nil function valid(f, o) if UnitExists(f) and not UnitIsDeadOrGhost(f) and UnitCanAttack(&quot;player&quot;, f) == 1 and UnitDebuffID(&quot;target&quot;, 33786) == nil and IsSpellInRange(GetSpellInfo(o), f) == 1 then return true else return false end end
