RuneCD = nil function RuneCD() local p = 0 for c = 1, 6 do if select(3, GetRuneCooldown(c)) == false then p = p + 1 end end return p end DeathRuneCD = nil function DeathRuneCD() local q = 0 local r = 0 for c = 1, 6 do if GetRuneType(c) == 4 and select(3, GetRuneCooldown(c)) == false then q = q + 1 elseif GetRuneType(c) == 4 and select(3, GetRuneCooldown(c)) == true then r = r + 1 end end return q, r end FrostRuneCD = nil function FrostRuneCD() local s = 0 local t = 0 for c = 1, 6 do if GetRuneType(c) == 2 and select(3, GetRuneCooldown(c)) == false then s = s + 1 elseif GetRuneType(c) == 2 and select(3, GetRuneCooldown(c)) == true then t = t + 1 end end return s, t end UnholyRuneCD = nil function UnholyRuneCD() local u = 0 local v = 0 for c = 1, 6 do if GetRuneType(c) == 3 and select(3, GetRuneCooldown(c)) == false then u = u + 1 elseif GetRuneType(c) == 3 and select(3, GetRuneCooldown(c)) == true then v = v + 1 end end return u, v end BloodRuneCD = nil function BloodRuneCD() local w = 0 local x = 0 for c = 1, 6 do if GetRuneType(c) == 1 and select(3, GetRuneCooldown(c)) == false then w = w + 1 elseif GetRuneType(c) == 1 and select(3, GetRuneCooldown(c)) == true then x = x + 1 end end return w, x end runpow = nil function runpow(o) local y = UnitPower(&quot;player&quot;) if y &gt;= select(4, GetSpellInfo(o)) then return true else return false end end functionsloaded = true if not PQR_StatusOverlayLib then PQR_StatusOverlayLib = true if PQR_OverlayBuffEnabled == nil then PQR_OverlayBuffEnabled = false end function PQR_CreateStatusOverlay() if PQR_StatusOverlayFrame then return end local f = CreateFrame("Frame", "PQR_StatusOverlayFrame", UIParent) PQR_StatusOverlayFrame = f f:SetWidth(280) f:SetHeight(138) f:SetPoint("TOP", UIParent, "TOP", 0, -28) f:SetFrameStrata("MEDIUM") local bg = f:CreateTexture(nil, "BACKGROUND") bg:SetAllPoints() bg:SetTexture(0, 0, 0, 0.55) local t = f:CreateFontString(nil, "OVERLAY", "GameFontNormalSmall") t:SetPoint("TOPLEFT", f, "TOPLEFT", 8, -6) t:SetJustifyH("LEFT") t:SetTextColor(1, 1, 1, 1) PQR_StatusOverlayTitle = t t:SetText("PQR") local l1 = f:CreateFontString(nil, "OVERLAY", "GameFontNormalSmall") l1:SetPoint("TOPLEFT", f, "TOPLEFT", 8, -22) l1:SetJustifyH("LEFT") PQR_StatusOverlayLine1 = l1 local l2 = f:CreateFontString(nil, "OVERLAY", "GameFontNormalSmall") l2:SetPoint("TOPLEFT", f, "TOPLEFT", 8, -38) l2:SetJustifyH("LEFT") PQR_StatusOverlayLine2 = l2 local l3 = f:CreateFontString(nil, "OVERLAY", "GameFontNormalSmall") l3:SetPoint("TOPLEFT", f, "TOPLEFT", 8, -54) l3:SetJustifyH("LEFT") PQR_StatusOverlayLine3 = l3 local cbR = CreateFrame("CheckButton", "PQR_StatusOverlay_cbRot", f, "UICheckButtonTemplate") cbR:SetPoint("TOPLEFT", f, "TOPLEFT", 4, -68) cbR:SetScript("OnClick", function(self) StopRota = not self:GetChecked() end) _G[cbR:GetName().."Text"]:SetText("Rotation enabled") PQR_StatusOverlay_cbRot = cbR local cbA = CreateFrame("CheckButton", "PQR_StatusOverlay_cbAoE", f, "UICheckButtonTemplate") cbA:SetPoint("TOPLEFT", f, "TOPLEFT", 4, -88) cbA:SetScript("OnClick", function(self) if AoE ~= nil then AoE = self:GetChecked() end end) _G[cbA:GetName().."Text"]:SetText("AoE mode") PQR_StatusOverlay_cbAoE = cbA local cbB = CreateFrame("CheckButton", "PQR_StatusOverlay_cbBuff", f, "UICheckButtonTemplate") cbB:SetPoint("TOPLEFT", f, "TOPLEFT", 4, -108) cbB:SetScript("OnClick", function(self) PQR_OverlayBuffEnabled = self:GetChecked() end) _G[cbB:GetName().."Text"]:SetText("Extra toggle (profile hook)") PQR_StatusOverlay_cbBuff = cbB PQR_OverlayHUD_Accum = 0 f:SetScript("OnUpdate", function(self, elapsed) PQR_OverlayHUD_Accum = PQR_OverlayHUD_Accum + elapsed if PQR_OverlayHUD_Accum >= 0.15 then PQR_OverlayHUD_Accum = 0 if PQR_UpdateStatusOverlay then PQR_UpdateStatusOverlay() end end end) end function PQR_UpdateStatusOverlay() if not PQR_StatusOverlayFrame then PQR_CreateStatusOverlay() end local _, class = UnitClass("player") PQR_StatusOverlayTitle:SetText(class or "PQR") local sbad = StopRota and "|cffff4444STOPPED|r" or "|cff44ff44RUNNING|r" PQR_StatusOverlayLine1:SetText("Rotation: "..sbad) local aoeStr = "" if AoE ~= nil then aoeStr = (AoE == true) and "|cff44ff44AoE ON|r" or "|cffff8888AoE OFF|r" elseif type(AOE) == "function" then aoeStr = AOE() and "|cff44ff44AoE ON|r" or "|cffff8888AoE OFF|r" else aoeStr = "|cffaaaaaaAoE n/a|r" end PQR_StatusOverlayLine2:SetText(aoeStr) local parts = {} if MS ~= nil then table.insert(parts, (MS == true) and "Mind Sear |cff44ff44ON|r" or "Mind Sear |cffff8888OFF|r") end if HN ~= nil then table.insert(parts, (HN == true) and "Hurricane |cff44ff44ON|r" or "Hurricane |cffff8888OFF|r") end if VoL ~= nil then table.insert(parts, (VoL == true) and "Volley |cff44ff44ON|r" or "Volley |cffff8888OFF|r") end if COL ~= nil then table.insert(parts, (COL == true) and "Chain Lightning |cff44ff44ON|r" or "Chain Lightning |cffff8888OFF|r") end if Heal ~= nil then table.insert(parts, (Heal == true) and "Chain Heal spam |cff44ff44ON|r" or "Chain Heal spam |cffff8888OFF|r") end if ELE ~= nil then table.insert(parts, (ELE == true) and "Elem mode |cff44ff44ON|r" or "Elem mode |cffff8888OFF|r") end if SoC ~= nil or RoF ~= nil then local s = "" if SoC ~= nil then s = (SoC == true) and "SoC |cff44ff44ON|r" or "SoC |cffff8888OFF|r" end if RoF ~= nil then s = s..((s ~= "") and " " or "")..((RoF == true) and "RoF |cff44ff44ON|r" or "RoF |cffff8888OFF|r") end table.insert(parts, s) end if Opener ~= nil then table.insert(parts, Opener and "Opener: Garrote" or "Opener: Ambush") end local extra = (#parts > 0) and table.concat(parts, " | ") or " " PQR_StatusOverlayLine3:SetText(extra) if PQR_StatusOverlay_cbRot then PQR_StatusOverlay_cbRot:SetChecked(StopRota ~= true) end if PQR_StatusOverlay_cbAoE then if AoE ~= nil then PQR_StatusOverlay_cbAoE:Show() PQR_StatusOverlay_cbAoE:SetChecked(AoE == true) else PQR_StatusOverlay_cbAoE:Hide() end end if PQR_StatusOverlay_cbBuff then PQR_StatusOverlay_cbBuff:SetChecked(PQR_OverlayBuffEnabled == true) end end end end

